### Load game data


::: {.cell}

```{.r .cell-code}
library(rlang)
library(cbbplotR)
# wab data from this repo: 
# https://github.com/gallochris/evdev-byc/blob/main/data/college-basketball/wab_logs.R

wab_today <- readr::read_csv("wab-today.csv")

teams_to_show <- readr::read_csv("full_wab.csv") |> 
  dplyr::filter(trk_wab < 26 & net_wab < 26) |> 
  dplyr::pull(team)

games <- readr::read_csv("https://raw.githubusercontent.com/gallochris/evdev-byc/refs/heads/main/data/cbb_daily_gamelog.csv")
```
:::


### WAB square table 


::: {.cell}

```{.r .cell-code}
wab_tbl <- wab_today |> 
  dplyr::filter(team %in% teams_to_show) |> 
  dplyr::mutate(conf_total = paste0(conf, ": ", round(league, 2), " | NC: ", 
                                    round(non_con, 2))) |> 
  dplyr::select(team, conf_total, league, non_con) |> 
  dplyr::mutate(
    league = ceiling(league),
    non_con = ceiling(non_con),
    dplyr::across(c(league, non_con), ~ purrr::map(.x, ~ ifelse(seq_len(5) <= .x, 1, NA)), .names = "{.col}_vec")
  ) |>
  tidyr::unnest_wider(league_vec, names_sep = "_") |>
  tidyr::unnest_wider(non_con_vec, names_sep = "_") |>
  dplyr::rename_with(~ paste0("league_", seq_along(.)), starts_with("league_vec")) |>
  dplyr::rename_with(~ paste0("nc_", seq_along(.)), starts_with("non_con_vec")) |> 
  dplyr::select(-league, -non_con) |> 
  dplyr::mutate(
    dplyr::across(starts_with("league_"), ~ dplyr::if_else(.x == 1, 0, .x))
  ) |> 
  dplyr::select(league_5, league_4, league_3, league_2, league_1,
                team, conf_total,
                nc_1, nc_2, nc_3, nc_4, nc_5)


wab_header <- glue::glue(
  "<div style='display: flex; justify-content: space-between; align-items: center;'>
      <div>
       <img src='https://a.espncdn.com/combiner/i?img=/redesign/assets/img/icons/ESPN-icon-basketball.png'
       style='height: 40px; width: auto; vertical-align: middle;'>
     </div>
     <div style='flex-grow:1; margin-left: 30px; margin-right: 30px'>
       <span style='display: block; font-weight: bold; text-align: center; font-size: 24px;'>Leaders in Wins-Above-Baseline <br><span style='color: #e66101'>Conference</span> | <span style='color: #1f78b4'>Non-Conference</span></span>
       <span style='font-size: 14px; font-weight: normal; display: block; text-align: center;'>Shows the teams with the highest WAB and compares the totals from conference and non-conference games through February 13.</span>
     </div>
     <div>
       <img src='https://a.espncdn.com/combiner/i?img=/redesign/assets/img/icons/ESPN-icon-basketball.png'
       style='height: 40px; width: auto; vertical-align: middle;'>
     </div>
   </div>
  <br>"
)


wab_plot <- wab_tbl |> 
  dplyr::ungroup() |> 
  cbbplotR::gt_cbb_teams(team, team) |> 
    gt::gt(
    groupname_col = c("conf")
    ) |> 
  gtExtras::gt_merge_stack(col1 = team, col2 = conf_total,
                           palette = c("black", "#333333"),
                           small_cap = FALSE) |> 
  gtUtils::gt_indicator_boxes(key_columns = "team",
                              color_yes = "#1f78b4",
                              color_no = "#e66101",
                              color_na = "#e1e1e1") |> 
gtUtils::gt_theme_gtutils() |>  
gt::fmt_markdown(team) |> 
gt::cols_align(team, align = "center") |> 
  gt::cols_label(team = "",
                 league_5 = "", 
                 league_4 = "", 
                 league_3 = "",
                 league_2 = "",
                 league_1 = "",
                 nc_1 = "", 
                 nc_2 = "", 
                 nc_3 = "", 
                 nc_4 = "", 
                 nc_5 = ""
                 ) |> 
   gt::tab_header(title = gt::html(wab_header)) |>
  gt::tab_source_note(
    source_note =
      gt::html(
        "<hr>WAB computed via data from barttorvik.com. The totals are rounded up to create <em>whole</em> numbers for the squares.<hr>Theme via {gtUtils} and logos from ESPN.<hr><b>Table by Chris at Bless your chart | data through February 13 games</b>"
      )
  ) |>
  gtUtils::gt_border_bars_bottom(c("#636363", "#969696", "#cccccc")) |> 
  gt::tab_options(table.width = gt::px(575)) |>
   gt::tab_style(
    locations = gt::cells_source_notes(),
    style = gt::cell_text(
      font = gt::google_font("Signika Negative"),
      size = gt::px(11.5),
      weight = 250
    )
  ) |>
  gt::tab_style(
    style = list(gt::cell_text(font = gt::google_font("Signika Negative"),
                               size = gt::px(15.5))),
    locations = gt::cells_body(columns = c(team, conf_total))
  ) 

gtUtils::gt_save_crop(wab_plot,
                      file = "wab_tbl.png",
                      whitespace = 60,
                      bg = "#FFFDF5")

wab_plot
```

