games_by_type <- games |> 
    dplyr::distinct(game_id, .keep_all = TRUE) |> 
    dplyr::group_by(date, type) |> 
    dplyr::summarise(count = dplyr::n(), .groups = "drop") |> 
    tidyr::complete(date = seq(min(date), max(date), by = "day"), type, fill = list(count = 0)) |>  
    dplyr::group_by(type) |> 
    dplyr::arrange(date, .by_group = TRUE) |> 
    dplyr::mutate(cumulative = cumsum(count)) |> 
    dplyr::ungroup()

